// 1. Capturamos el HTML crudo entregado por el Nodo 1
const htmlPuro = $input.first().json.data;
const enlacesEncontrados = [];

// Expresión regular elástica: Busca cualquier URL entre comillas que contenga "RegistrosAdministrativos" y termine en ".csv"
// Sin importar si dice MINEDUC, MINEDEC, tiene guiones bajos o errores de tipeo.
const regexExtractorUrls = /href="([^"]*RegistrosAdministrativos[^"]*\.csv)"/gi;

let coincidencia;
// Buscamos todas las URLs coincidentes dentro del HTML de la página
while ((coincidencia = regexExtractorUrls.exec(htmlPuro)) !== null) {
  const urlCompleta = coincidencia[1];

  // Expresión regular para extraer los años fiscales del archivo (ej: "2025-2026")
  const regexAnio = /(\d{4})-\d{4}/;
  const matchAnio = urlCompleta.match(regexAnio);

  if (matchAnio) {
    // Tomamos el año de inicio (ej: "2025") y lo convertimos a entero para poder ordenarlo matemáticamente
    const anioBase = parseInt(matchAnio[1], 10);

    enlacesEncontrados.push({
      url: urlCompleta,
      anio: anioBase
    });
  }
}

if (enlacesEncontrados.length === 0) {
  throw new Error("Control de Contingencia: No se detectaron enlaces CSV válidos en el código fuente de la página.");
}

// 2. ORDENACIÓN CRONOLÓGICA INVERSA (De mayor a menor año)
// Esto garantiza que el año más actual (ej: 2025) quede siempre en la posición [0]
enlacesEncontrados.sort((a, b) => b.anio - a.anio);

// Aislamos el registro ganador
const descargaMasReciente = enlacesEncontrados[0];

// Retornamos el payload normalizado para los siguientes nodos del pipeline
return [{
  json: {
    INDICADOR: "MINEDUC_AMIE_COSTA",
    FECHA_FISCAL: descargaMasReciente.anio.toString(), // Guardará "2025", "2026", etc.
    URL_CSV_DINAMICO: descargaMasReciente.url,       // ◄--- La URL real mutada y corregida del Ministerio
    ESTADO: "COMPLETO",
    NECESITA_RESPALDO: 0,
    DETALLE_ERROR: ""
  }
}];

const rawItems = $input.all();
const listaConsolidada = [];

// Expresión regular para capturar dinámicamente cualquier año (ej: 2022, 2030) en las cabeceras
const regexAnioDinamico = /\b(20\d{2})\b/; 
let anioDetectado = null;

// =========================================================================
// FASE 1: ESCANEO DINÁMICO DE CABECERAS (Busca el año real del documento)
// =========================================================================
for (let i = 0; i < Math.min(rawItems.length, 20); i++) {
  const filaData = rawItems[i].json;
  for (const propiedad in filaData) {
    const textoCelda = String(filaData[propiedad]);
    const coincidencia = textoCelda.match(regexAnioDinamico);

    if (coincidencia) {
      anioDetectado = coincidencia[1]; // Captura el año (ej: "2022")
      break;
    }
  }
  if (anioDetectado) break; // Si ya lo encontramos, detenemos el escaneo preliminar
}

// Fallback de seguridad en caso de que el archivo venga corrupto o sin títulos
if (!anioDetectado) {
  anioDetectado = "2022"; 
}

// Función auxiliar para limpiar y parsear enteros del INEC
function parsearNumeroCenso(val) {
  if (val === undefined || val === null || val === '') return null;
  if (typeof val === 'number') return val;
  const limpio = val.toString().replace(/\./g, '').trim();
  const num = parseInt(limpio, 10);
  return isNaN(num) ? null : num;
}

// =========================================================================
// FASE 2: PROCESAMIENTO Y TRADUCCIÓN DE LA MATRIZ CENSAL
// =========================================================================
for (const item of rawItems) {
  const data = item.json;

  const provincia = data.__EMPTY ? data.__EMPTY.toString().trim() : "";
  const canton = data.__EMPTY_1 ? data.__EMPTY_1.toString().trim() : "";
  const sexo = data.__EMPTY_3 ? data.__EMPTY_3.toString().trim() : "";  
  const edad = data.__EMPTY_4 ? data.__EMPTY_4.toString().trim() : "";  

  // Escudo contra filas de basura, títulos e índices
  if (!sexo || sexo.includes("sexo") || sexo === "Sexo" || sexo === "" || provincia.includes("Índice")) {
    continue;
  }
  if (!edad || edad.includes("edad") || edad === "Edad" || edad === "") {
    continue;
  }

  // CONSTRUCCIÓN DE LA LLAVE ÚNICA CON EL AÑO DETECTADO DINÁMICAMENTE
  // Si mañana el INEC sube el censo 2030, esta llave mutará sola a: "2030_Azuay_Cuenca..."
  const llaveCompuesta = `${anioDetectado}_${provincia}_${canton}_${sexo}_${edad}`.replace(/\s+/g, '');
  const fechaFiscalClave = llaveCompuesta.substring(0, 50); 

  listaConsolidada.push({
    json: {
      INDICADOR: "CENSO_RAMA_ACTIVIDAD", // Nombre genérico para admitir múltiples censos en la misma tabla
      FECHA_FISCAL: fechaFiscalClave,   
      FECHA_EXTRACCION: new Date(),     
      ESTADO: "COMPLETO",
      NECESITA_RESPALDO: 0,
      DETALLE_ERROR: "",
      DATOS_JSON: JSON.stringify({
        anio_censo: parseInt(anioDetectado, 10), // Guardado dinámico como entero
        provincia: provincia,
        canton: canton,
        sexo: sexo,
        rango_edad: edad,
        total_ocupados: parsearNumeroCenso(data.__EMPTY_5), 
        ramas_actividad: {
          agricultura_pesca: parsearNumeroCenso(data.__EMPTY_6),
          minas_canteras: parsearNumeroCenso(data.__EMPTY_7),
          industrias_manufactureras: parsearNumeroCenso(data.__EMPTY_8),
          electricidad_gas: parsearNumeroCenso(data.__EMPTY_9),
          agua_saneamiento: parsearNumeroCenso(data.__EMPTY_10),
          construccion: parsearNumeroCenso(data.__EMPTY_11),
          comercio: parsearNumeroCenso(data.__EMPTY_12),
          transporte_almacenamiento: parsearNumeroCenso(data.__EMPTY_13),
          alojamiento_comidas: parsearNumeroCenso(data.__EMPTY_14),
          informacion_comunicacion: parsearNumeroCenso(data.__EMPTY_15),
          financieras_seguros: parsearNumeroCenso(data.__EMPTY_16),
          inmobiliarias: parsearNumeroCenso(data.__EMPTY_17),
          profesionales_cientificas: parsearNumeroCenso(data.__EMPTY_18),
          servicios_administrativos: parsearNumeroCenso(data.__EMPTY_19),
          administracion_publica: parsearNumeroCenso(data.__EMPTY_20),
          ensenanza: parsearNumeroCenso(data.__EMPTY_21),
          salud_asistencia: parsearNumeroCenso(data.__EMPTY_22),
          arte_entretenimiento: parsearNumeroCenso(data.__EMPTY_23),
          otros_servicios: parsearNumeroCenso(data.__EMPTY_24),
          hogares_empleadores: parsearNumeroCenso(data.__EMPTY_25),
          organizaciones_extraterritoriales: parsearNumeroCenso(data.__EMPTY_26),
          no_clasificado: parsearNumeroCenso(data.__EMPTY_27) 
        },
        fuente: "Instituto Nacional de Estadística y Censos (INEC)",
        ruta_logica: "INEC/CENSO_POBLACION/RAMAS_ACTIVIDAD"
      })
    }
  });
}

return listaConsolidada;

