// Soportamos el salto de línea estándar de archivos CSV (\n o \r\n)
const lineas = archivoPlanoText.toString('utf-8').split(/\r?\n/);
const listaFilasProcesadas = [];

// Función para limpiar celdas y parsear números enteros con puntos de miles o guiones vacíos
function parsearNumeroMineduc(val) {
  if (val === undefined || val === null) return 0;
  // Eliminamos espacios en blanco comunes y espacios de no ruptura (\u00A0)
  let limpio = val.toString().replace(/[\s\u00A0]/g, '').trim();
  // Si la celda contiene el guion de ausencia o está vacía, su valor lógico es 0
  if (limpio === '-' || limpio === '' || limpio === '.-') return 0;
  // Removemos los puntos de miles para que JavaScript no lo trate como decimal
  limpio = limpio.replace(/\./g, '');
  const num = parseInt(limpio, 10);
  return isNaN(num) ? 0 : num;
}

// Empezamos en el índice 1 para saltarnos la fila de cabeceras (headers)
for (let i = 1; i < lineas.length; i++) {
  const filaCruda = lineas[i];
  if (!filaCruda.trim()) continue; // Ignoramos líneas vacías al final del documento

  // Separamos las columnas por punto y coma (;) según la especificación de la fuente
  const celdas = filaCruda.split(';');

  // Validación de seguridad: Si la fila no tiene al menos el código AMIE, está corrupta
  const amieCodigo = celdas[1] ? celdas[1].trim() : "";
  if (!amieCodigo || amieCodigo === "AMIE") continue;

  // EXTRAER EL AÑO BASE DE FORMA DINÁMICA
  // "2025-2026 Inicio" -> Tomamos los primeros 4 dígitos ("2025") para mantener la coherencia cronológica
  const anioLectivoRaw = celdas[0] ? celdas[0].trim() : "";
  const matchAnio = anioLectivoRaw.match(/^(\d{4})/);
  const anioFiscal = matchAnio ? matchAnio[1] : "2025";

