// 1. Capturamos el ítem de error que activó el nodo
const rawItem = $input.first().json;
const hoy = new Date();

// 2. Formateamos una fecha de salvavidas para la FECHA_FISCAL (YYYY-MM-DD)
const anio = hoy.getFullYear();
const mes = String(hoy.getMonth() + 1).padStart(2, '0');
const dia = String(hoy.getDate()).padStart(2, '0');
const fechaFallback = `${anio}-${mes}-${dia}`;

let mensajeError = "Fallo indeterminado en la conectividad con la fuente anual.";
let urlAfectada = "";

// Extraemos el mensaje técnico y la URL del objeto de error de n8n
if (rawItem.error) {
  mensajeError = rawItem.error.message || JSON.stringify(rawItem.error);
  urlAfectada = rawItem.error.context?.url || "";
} else if (rawItem.message) {
  mensajeError = rawItem.message;
}

// 3. ALGORITMO DE CLASIFICACIÓN DE FUENTES ANUALES
// Escaneamos el rastro de texto para identificar cuál de las 4 fuentes falló
let indicadorTarget = "ANUAL_DESCONOCIDO";
let rutaLogicaTarget = "COYUNTURA/ANUAL/CONTINGENCIA";

const rastroTexto = (mensajeError + " " + urlAfectada).toLowerCase();

if (rastroTexto.includes("bce") || rastroTexto.includes("cuentasnacionales") || rastroTexto.includes("fin.ec")) {
  indicadorTarget = "BCE_CUENTAS_NACIONALES";
  rutaLogicaTarget = "BCE/CUENTAS_NACIONALES/ANUAL";
} 
else if (rastroTexto.includes("ranking") || rastroTexto.includes("supercias") || rastroTexto.includes("appscvsmovil")) {
  indicadorTarget = "SUPERCIAS_RANKING";
  rutaLogicaTarget = "SUPERCIAS/RANKING/INGRESOS_VENTAS";
} 
else if (rastroTexto.includes("censo") || rastroTexto.includes("censoecuador") || rastroTexto.includes("tabulados")) {
  indicadorTarget = "INEC_CENSO_2022";
  rutaLogicaTarget = "INEC/CENSO_2022/ESTATICA";
} 
else if (rastroTexto.includes("educacion.gob.ec") || rastroTexto.includes("amie") || rastroTexto.includes("registrosadministrativos")) {
