function procesarValorFinanciero(val) {
  if (val === undefined || val === null) return null;
  const limpio = val.toString().trim();
  if (limpio === '' || limpio === '-' || limpio === 'null') return null;

  const num = Number(limpio);
  return isNaN(num) ? limpio : num; // Si es numérico lo convierte, sino conserva el texto
}

